/// Stable catalog entry used by the redesigned browser.
///
/// This is intentionally separate from [FractalModule] so we can scale the
/// catalog to many entries (e.g. PRD 200) while still mapping to currently
/// implemented render modules.
@immutable
class CatalogEntry {
  /// Stable ID for catalog persistence, analytics, and deep links.
  ///
  /// Must never change once published.
  final String catalogId;

  /// Backing runtime fractal module that can render this entry today.
  final FractalModule module;

  /// Display category used to group entries in the catalog UI.
  final String category;

  /// Optional search aliases used by catalog filtering.
  final List<String> aliases;

  const CatalogEntry({
    required this.catalogId,
    required this.module,
    required this.category,
    this.aliases = const [],
  });
}

import 'dart:async';

/// Cancelable debounce contract for catalog search input.
///
/// A search edit should publish only after [delay] has elapsed without a newer
/// edit. Keeping this behavior behind a small helper makes the timing contract
/// testable instead of relying on stacked [Future.delayed] callbacks.
final class CatalogSearchDebouncer {
  final Duration delay;
  Timer? _timer;

  CatalogSearchDebouncer({
    this.delay = const Duration(milliseconds: 300),
  });

  void schedule(void Function() callback) {
    _timer?.cancel();
    _timer = Timer(delay, callback);
  }

  void cancel() {
    _timer?.cancel();
    _timer = null;
  }

  void dispose() {
    cancel();
  }
}

