                : AppColors.border.withValues(alpha: 0.5),
            borderRadius: BorderRadius.circular(AppSpacing.buttonRadius),
          ),
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              Icon(
                icon,
                size: 16,
                color: isPressed ? AppColors.primary : AppColors.textSecondary,
